      TECHNICAL: { base: "2D", skills: { "capital ship repair": "4D", "capital ship weapon repair": "4D", "computer programming/repair": "6D", demolitions: "3D", "droid programming": "6D", "droid repair": "5D", "first aid": "6D", "ground vehicle repair": "3D", "repulsorlift repair": "3D", security: "7D", "starship repair": "4D" } }
