      KNOWLEDGE: { base: "3D", skills: { "alien species": "7D+1", "bureaucracy": "8D+1", "cultures": "5D", "intimidation": "5D+1", "languages": "6D", "planetary systems": "8D", "survival": "4D", "survival: ocean/undersea": "6D", "tactics: capital ships": "9D", "tactics: fleets": "9D+2", "tactics: starfighters": "7D+1", "value": "5D+2", "willpower": "6D" } },
