      KNOWLEDGE: { base: "2D", skills: { "alien species": "5D", "bureaucracy": "6D+2", "business": "6D", "cultures": "6D", "intimidation": "5D+1", "languages": "8D+2", "law enforcement": "7D", "planetary systems": "5D", "streetwise": "5D+2", "survival": "4D+1", "value": "5D", "willpower": "4D+2" } },
