      TECHNICAL: { base: "2D+1", skills: { "computer programming/repair": "4D", "demolition": "5D+1", "droid programming": "5D+1", "ground vehicle repair": "5D", "hover vehicle repair": "4D+2", "first aid": "6D", "security": "8D", "space transports repair": "6D", "starfighter repair": "5D" } }
