      MECHANICAL: { base: "2D", skills: { "astrogation": "2D+2", "ground vehicle operation": "2D+2", "hover vehicle operation": "3D" } },
      PERCEPTION: { base: "3D+2", skills: { "bargain": "4D+1", "command": "4D+2", "con": "4D+2", "forgery": "4D+1", "persuasion": "4D+1" } },
