      KNOWLEDGE: { base: "3D", skills: { "business": "4D+1", "cultures": "3D+2", "planetary systems": "4D" } },
      MECHANICAL: { base: "3D", skills: { "repulsorlift operation": "5D" } },
      PERCEPTION: { base: "4D", skills: { "bargain": "5D", "con": "7D+1", "gambling": "7D" } },
      STRENGTH: { base: "3D", skills: { "brawling": "4D" } },
