      PERCEPTION: { base: "3D+2", skills: { "Bargain": "7D", "Command": "10D", "Command: Hapan troops": "12D+2", "Con": "4D", "Forgery: ship IDs": "6D", "Forgery: Imperial port codes": "7D", "Hide": "6D", "Persuasion": "8D", "Search": "6D", "Sneak": "6D+1" } },
