      MECHANICAL: { base: "3D", skills: {} },
      PERCEPTION: { base: "3D+2", skills: { "bargain": "5D", "command": "4D+2", "con": "5D+2", "forgery": "5D", "gambling": "6D+2", "hide": "7D", "persuasion": "4D" } },
