      STRENGTH: { base: "3D", skills: { "brawling": "5D", "climbing/jumping": "6D" } },
      TECHNICAL: { base: "2D", skills: { "computer programming/repair": "6D+2", "demolition": "5D", "security": "6D+1" } }
